// Get all products
const products = $input.all();

// Initialize arrays
const low_stock = [];
const urgent_low_stock = [];

// Define thresholds
const thresholds = {
  "headphones": 10,
  "gaming-laptops": 7,
  "laptops": 10,
  "fashion": 15,
  "mobile-phones": 10,
  "monitors": 8,
  "default": 7
};

const urgentThresholds = {
  "headphones": 5,
  "gaming-laptops": 3,
  "laptops": 4,
  "fashion": 8,
  "mobile-phones": 5,
  "monitors": 4,
  "default": 3
};

// Process each product
for (const item of products) {
  const product = item.json;

  // Skip if stock is not managed or stock quantity is null
  if (!product.manage_stock || product.stock_quantity === null) {
    continue;
  }

  const categories = product.categories;

  // Determine category
  let category = "default";
  if (Array.isArray(categories) && categories.length === 1) {
    category = categories[0].slug.toLowerCase();
  }

  // Get thresholds
  const threshold = thresholds[category] || thresholds["default"];
  const urgentThreshold = urgentThresholds[category] || urgentThresholds["default"];

  // Create product object
  const productData = {
    "product": product.name,
    "current_stock": product.stock_quantity,
    "Category": product.categories.map(cat => cat.name).join(', ')
  };

  // Check stock levels and add to appropriate array
  if (product.stock_quantity <= urgentThreshold) {
    urgent_low_stock.push(productData);
  } else if (product.stock_quantity <= threshold) {
    low_stock.push(productData);
  }
}

// Return the accumulated results
return {
  json: {
    low_stock: low_stock,
    uregent_low_stock: urgent_low_stock
  }
};

// Extracting the urgent low stock items
const urgentLowStock = $input.first().json.uregent_low_stock;

// Building the message
let message = "Below are the list of products whose stock is very low and we need to refill it as soon as possible,\n\n";

urgentLowStock.forEach((item, index) => {
  message += `${index + 1}. ${item.product} -> current stock: ${item.current_stock}\n`;
});

message += "\nPlease take action to avoid stockouts.";

// Output the message
return { description : message };
